import{_ as l,c as i,a3 as t,o as a}from"./chunks/framework.CAwIQbWu.js";const m=JSON.parse('{"title":"爆胎篇","description":"","frontmatter":{},"headers":[],"relativePath":"SubjectOne/常识/爆胎篇.md","filePath":"SubjectOne/常识/爆胎篇.md","lastUpdated":1736413709000}'),o={name:"SubjectOne/常识/爆胎篇.md"};function r(n,e,s,c,d,p){return a(),i("div",null,e[0]||(e[0]=[t('<h1 id="爆胎篇" tabindex="-1">爆胎篇 <a class="header-anchor" href="#爆胎篇" aria-label="Permalink to &quot;爆胎篇&quot;">​</a></h1><ol><li>行车中爆胎，若立即紧急制动，容易导致翻车，引发交通事故。</li><li>行车中爆胎，车辆会偏移，要紧握方向盘控制好方向，轻踏踏板缓慢减速靠边停车。</li><li>道路平坦，突然颠簸说明轮胎可能出问题了，要降速找安全的地方停车检查。</li><li>行车中突然爆胎，可利用发动机制动，即从高位挡迅速换到低位挡来减速。</li><li>车辆前轮负责转向，行车中前轮爆胎，车辆会立即偏向爆胎一侧。</li><li>气压过高或过低都会导致爆胎，所以降低轮胎气压是错误的。</li><li>轮胎胎压有指标，低于指标就会爆胎，所以不能随便降低轮胎气压。</li><li>定期检查和清理轮胎，及时更换有裂纹的轮胎，可有效防止爆胎。</li><li>行车中爆胎后，猛打转向盘和紧急制动都很容易翻车。</li><li>降低胎压不能有效避免爆胎，反而会增加爆胎风险。</li><li>轮胎漏气、气压过低或过高或车辆严重超载都可能导致爆胎。</li></ol>',2)]))}const u=l(o,[["render",r]]);export{m as __pageData,u as default};
